// FireCorporationMemberComposer.ts
import { IMessageComposer } from '@nitrots/nitro-renderer';

export class FireCorporationMemberComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(corporationId: number, targetUserId: number) {
        this._data = [corporationId, targetUserId];
        console.log('[📤] FireCorporationMemberComposer:', this._data);
    }

    public getMessageArray(): any[] {
        return this._data;
    }
    public dispose(): void {
        /* no-op */
    }
}
